            for (window.panes.items) |pane| {
                if (pane.fd >= 0) {
                    gcd.addFd(pane.fd, .read, cb) catch {};
                }
            }
        }
    }

    // Register existing client fds.
    for (self.clients.items) |client| {
        if (client.fd >= 0) {
            gcd.addFd(client.fd, .read, cb) catch {};
        }
    }

